            print(f'  {proj}: {pkg} {bv} -> {av}')
if not changes:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for proj in sorted(b.keys()):
    for pkg in sorted(b[proj].keys()):
        bv = b[proj][pkg]
        av = a.get(proj, {}).get(pkg)
        if bv == av:
            print(f'  {proj}: {pkg} {bv}')
